//! Full AMI pipeline orchestrator: build → test → cluster-test → promote (or rollback).
//!
//! Replaces the shell script in substrate's `mkAmiBuildPipeline` with a
//! single Rust binary. Packer handles SSH, instance lifecycle, and cleanup.
//! This module orchestrates the Packer invocations and post-build actions.
//!
//! Configuration is read from a YAML file generated by Nix (shikumi pattern:
//! Nix option → YAML config file → Rust reads config). The `--config` flag
//! points to the pipeline config.

use anyhow::{bail, Context, Result};
use clap::Args;
use serde::Deserialize;
use std::path::{Path, PathBuf};
use std::process::Command;
use tracing::{error, info, warn};

use crate::attic;

/// Pins a nix store path alive for the pipeline's lifetime via a real
/// `nix-store` GC root, so a disk-pressure-triggered `nix-collect-garbage`
/// running concurrently on the *evaluating* machine (not the remote AMI
/// builder — this pipeline's own `build_template`/`test_template`/`config`
/// paths live on whichever box invoked `ami-forge pipeline-run`) can never
/// collect a path this run still needs between phases.
///
/// Root cause this closes: a `[1/N]` build phase pulling a large closure
/// from a substituter can run long enough to cross a local GC's disk-
/// pressure threshold; without a root, `test_template` (evaluated once at
/// pipeline start, only re-touched at `[3/N]`) can vanish from the store
/// in between — surfacing as `packer init failed: stat ... no such file or
/// directory` at the test phase, long after the real cause (an unrelated
/// GC sweep) has already happened and is invisible in the error itself.
///
/// `root_dir` must outlive every phase that reads the rooted paths — the
/// caller holds its `tempfile::TempDir` for the whole pipeline run, not
/// just this call.
fn add_gc_root(store_path: &Path, root_dir: &Path, root_name: &str) -> Result<()> {
    let root_link = root_dir.join(root_name);
    let status = Command::new("nix-store")
        .arg("--realise")
        .arg(store_path)
        .arg("--add-root")
        .arg(&root_link)
        .status()
        .with_context(|| format!("failed to invoke nix-store --add-root for {}", store_path.display()))?;
    if !status.success() {
        bail!(
            "nix-store --add-root failed for {} (exit {status}) -- \
             this path may be collected by a concurrent GC before the pipeline reaches it",
            store_path.display()
        );
    }
    Ok(())
}

/// Roots every pipeline-input path (`build_template`, `test_template`, and
/// `cluster_test.config` when present) under one `TempDir` for the whole
/// run. Returns the `TempDir` — the caller MUST hold it alive (not `_`-drop
/// it) until the pipeline finishes; dropping it removes the gcroots
/// directory and un-pins every path it protected.
fn root_pipeline_inputs(config: &PipelineConfig) -> Result<tempfile::TempDir> {
    let root_dir = tempfile::Builder::new()
        .prefix("ami-forge-gcroots-")
        .tempdir()
        .context("failed to create gcroots tempdir")?;
    add_gc_root(&config.build_template, root_dir.path(), "build-template")?;
    add_gc_root(&config.test_template, root_dir.path(), "test-template")?;
    if let Some(ref ct) = config.cluster_test {
        add_gc_root(&ct.config, root_dir.path(), "cluster-test-config")?;
    }
    Ok(root_dir)
}

#[derive(Args)]
pub struct PipelineRunArgs {
    /// Path to pipeline configuration YAML
    #[arg(long)]
    pub config: PathBuf,
}

#[derive(Deserialize)]
pub struct PipelineConfig {
    pub build_template: PathBuf,
    pub test_template: PathBuf,
    pub ssm: String,
    pub ami_name: String,
    #[serde(default = "default_region")]
    pub region: String,
    #[serde(default)]
    pub cluster_test: Option<ClusterTestRef>,
    #[serde(default = "default_manifest")]
    pub manifest: PathBuf,
    #[serde(default)]
    pub attic: Option<attic::AtticConfig>,
    /// When true, after the SSM put add a public LaunchPermission so
    /// any AWS account can launch the AMI without a per-account share.
    /// Off by default — only flip on for artifacts known to carry no
    /// secrets.
    #[serde(default)]
    pub make_public: bool,
}

#[derive(Deserialize)]
pub struct ClusterTestRef {
    pub config: PathBuf,
}

fn default_region() -> String {
    "us-east-1".into()
}
fn default_manifest() -> PathBuf {
    PathBuf::from("packer-manifest.json")
}

// ---------------------------------------------------------------------------
// Pipeline orchestrator
// ---------------------------------------------------------------------------

pub async fn run(args: PipelineRunArgs) -> Result<()> {
    let config_content = std::fs::read_to_string(&args.config)
        .with_context(|| format!("failed to read pipeline config: {}", args.config.display()))?;
    let config: PipelineConfig = serde_yaml::from_str(&config_content)
        .context("failed to parse pipeline config YAML")?;

    // Validate inputs
    if !config.build_template.exists() {
        bail!(
            "Build template not found: {}",
            config.build_template.display()
        );
    }
    if !config.test_template.exists() {
        bail!(
            "Test template not found: {}",
            config.test_template.display()
        );
    }

    // Root every pipeline-input path for the whole run -- held alive in
    // `_gcroots` (never dropped early) so a concurrent disk-pressure GC
    // can't collect `test_template`/etc. between phases. See `add_gc_root`.
    let _gcroots = root_pipeline_inputs(&config)?;

    let total_phases = if config.cluster_test.is_none() { 4 } else { 5 };

    // Validate AWS credentials early
    let aws_config = crate::aws::load_config(&config.region).await;
    let arn = crate::aws::validate_credentials(&aws_config).await?;
    info!("Pipeline starting as {arn}");

    // ── Reap expired instances/AMIs before starting ────────────
    info!("[reaper] Cleaning up expired ami-forge resources");
    let ec2_for_reap = aws_sdk_ec2::Client::new(&aws_config);
    if let Err(e) = crate::reaper::run_reaper(&ec2_for_reap).await {
        warn!("[reaper] Cleanup failed (non-fatal): {e}");
    }

    // ── Attic ephemeral cache (optional) ────────────────────────
    let mut attic_res: Option<attic::AtticResources> = None;
    if let Some(ref attic_cfg) = config.attic {
        info!("[attic] Booting ephemeral cache from {}", attic_cfg.ssm);
        let ec2_client = aws_sdk_ec2::Client::new(&aws_config);
        let ssm_client = aws_sdk_ssm::Client::new(&aws_config);
        match attic::attic_boot(&ec2_client, &ssm_client, attic_cfg).await {
            Ok(res) => match attic::attic_wait_healthy(&res.public_ip, 180).await {
                Ok(()) => {
                    attic_res = Some(res);
                }
                Err(e) => {
                    warn!("[attic] Health check failed (degrading without cache): {e:#}");
                    if let Err(te) = attic::attic_teardown(&ec2_client, &res).await {
                        warn!("[attic] Teardown of unhealthy instance also failed: {te:#}");
                    }
                }
            },
            Err(e) => {
                warn!("[attic] Boot failed (degrading without cache): {e:#}");
            }
        }
    }

    // Run the pipeline phases, capturing the result so Attic cleanup always runs.
    let pipeline_result =
        run_pipeline_phases(&config, &aws_config, &attic_res, total_phases).await;

    // ── Attic snapshot + teardown (ALWAYS -- cache grows richer) ─
    if let Some(ref res) = attic_res {
        let attic_cfg = config.attic.as_ref().expect("attic_res set implies config.attic is Some");
        let ec2_client = aws_sdk_ec2::Client::new(&aws_config);
        let ssm_client = aws_sdk_ssm::Client::new(&aws_config);
        if let Err(e) = attic::attic_snapshot(&ec2_client, &ssm_client, &res.instance_id, &attic_cfg.ssm).await {
            warn!("[attic] Snapshot failed (non-fatal): {e:#}");
        }
        if let Err(e) = attic::attic_teardown(&ec2_client, res).await {
            warn!("[attic] Teardown failed: {e:#}");
        }
    }

    pipeline_result
}

/// Inner pipeline phases, factored out so Attic cleanup always runs regardless
/// of success or failure.
async fn run_pipeline_phases(
    config: &PipelineConfig,
    aws_config: &aws_config::SdkConfig,
    attic_res: &Option<attic::AtticResources>,
    total_phases: usize,
) -> Result<()> {
    let github_token = std::env::var("GITHUB_TOKEN").unwrap_or_default();
    let build_tpl = config.build_template.to_string_lossy();
    let test_tpl = config.test_template.to_string_lossy();
    let manifest_path = config.manifest.to_string_lossy().to_string();

    // ── Phase 1: Build AMI ──────────────────────────────────────
    info!("[1/{total_phases}] Building AMI from base NixOS image");
    run_packer_init(&build_tpl)?;

    let mut build_vars = vec![format!("github_token={github_token}")];
    if let Some(ref res) = *attic_res {
        let cache_name = &config
            .attic
            .as_ref()
            .expect("attic_res set implies config.attic is Some")
            .cache_name;
        // Use private IP -- the build instance is in the same VPC as the Attic server
        build_vars.push(format!(
            "attic_url=http://{}:8080/{cache_name}",
            res.private_ip
        ));
        info!("[attic] Passing substituter URL to Packer build (private IP)");
    }
    run_packer_build(&build_tpl, &build_vars)?;

    // ── Phase 2: Extract AMI ID ─────────────────────────────────
    info!("[2/{total_phases}] Extracting AMI ID from manifest");
    let ami_id = crate::aws::parse_packer_manifest(&manifest_path)?;
    info!("Built AMI: {ami_id}");

    // ── Phase 3: Single-node smoke test (Packer) ────────────────
    info!("[3/{total_phases}] Running single-node integration test on {ami_id}");
    run_packer_init(&test_tpl)?;
    let test_result = run_packer_build(&test_tpl, &[format!("source_ami={ami_id}")]);

    if let Err(e) = test_result {
        error!("Single-node test FAILED: {e:#}");
        deregister_and_fail(aws_config, &config.ami_name, &manifest_path, &ami_id).await?;
    }

    // ── Phase 4: Multi-node cluster test ────────────────────────
    if let Some(ref ct) = config.cluster_test {
        info!("[4/{total_phases}] Running multi-node cluster integration test on {ami_id}");
        let cluster_args = crate::cluster_test::ClusterTestArgs {
            config: ct.config.clone(),
            ami_id: ami_id.clone(),
        };
        if let Err(e) = crate::cluster_test::run(cluster_args).await {
            error!("Cluster test FAILED: {e:#}");
            deregister_and_fail(aws_config, &config.ami_name, &manifest_path, &ami_id).await?;
        }
    }

    // ── Phase 5: Promote ────────────────────────────────────────
    let promote_phase = if config.cluster_test.is_none() { 4 } else { 5 };
    info!("[{promote_phase}/{total_phases}] Promoting AMI {ami_id} to {}", config.ssm);
    let ssm_client = aws_sdk_ssm::Client::new(aws_config);
    crate::aws::put_ssm_parameter(&ssm_client, &config.ssm, &ami_id).await?;

    if config.make_public {
        let ec2_client = aws_sdk_ec2::Client::new(aws_config);
        crate::aws::make_image_public(&ec2_client, &ami_id).await?;
    }

    cleanup_manifest(&manifest_path);
    info!(
        "Pipeline complete -- AMI {ami_id} promoted to {}",
        config.ssm
    );

    Ok(())
}

async fn deregister_and_fail(
    config: &aws_config::SdkConfig,
    ami_name: &str,
    manifest_path: &str,
    ami_id: &str,
) -> Result<()> {
    info!("Deregistering failed AMI: {ami_id}");
    let ec2 = aws_sdk_ec2::Client::new(config);
    match crate::rotate::run_rotate(&ec2, ami_name).await {
        Ok(()) => info!("Failed AMI deregistered"),
        Err(re) => warn!("AMI deregistration also failed: {re}"),
    }
    cleanup_manifest(manifest_path);
    bail!("AMI pipeline failed -- AMI deregistered");
}

fn run_packer_init(template: &str) -> Result<()> {
    let status = Command::new("packer")
        .args(["init", template])
        .status()
        .context("failed to execute packer init")?;
    if !status.success() {
        bail!("packer init failed for {template}");
    }
    Ok(())
}

fn run_packer_build(template: &str, vars: &[String]) -> Result<()> {
    let mut cmd = Command::new("packer");
    cmd.arg("build");
    // On error: clean up the builder instance instead of leaving it running.
    // This prevents orphaned instances when Packer encounters provisioner errors.
    cmd.args(["-on-error=cleanup"]);
    for var in vars {
        cmd.args(["-var", var]);
    }
    cmd.arg(template);
    let status = cmd.status().context("failed to execute packer build")?;
    if !status.success() {
        bail!("packer build failed for {template}");
    }
    Ok(())
}

fn cleanup_manifest(path: &str) {
    if std::path::Path::new(path).exists() {
        if let Err(e) = std::fs::remove_file(path) {
            warn!("Failed to remove manifest: {e}");
        }
    }
}

#[cfg(test)]
mod gc_root_tests {
    use super::*;

    /// A real, always-present nix store path to exercise `add_gc_root`
    /// against — resolved from the `nix-store` binary itself via `PATH`,
    /// not from this test binary's own `current_exe()`. `cargo test` is
    /// commonly invoked directly (not via `nix build`/`nix run`), in which
    /// case the test binary's own path sits under `target/debug/deps/...`,
    /// NOT `/nix/store` — an earlier version of this test used
    /// `current_exe()` and silently no-op'd (skipped) under a plain
    /// `cargo test`, which is exactly the class of "green but proves
    /// nothing" regression test this fix exists to avoid. `nix-store`
    /// itself has to exist under `/nix/store` for the rest of this
    /// pipeline to work at all (the whole point of `add_gc_root` is
    /// calling the `nix-store` binary), so resolving IT via `PATH` is a
    /// dependency this test already has either way, not an extra one.
    ///
    /// Deliberately returns the TOP-LEVEL `/nix/store/<hash>-<name>`
    /// component, not a nested file within it (e.g. `nix-store`'s own
    /// resolved binary lives at `.../determinate-nix-3.17.0/bin/nix` —
    /// a file *inside* that package's output). This distinction is
    /// load-bearing, not cosmetic: `nix-store --realise --add-root` on a
    /// nested file roots the *containing* top-level store path, not the
    /// exact file (caught live by this test's own first draft, which
    /// asserted equality against the nested path and failed) — but every
    /// REAL path `add_gc_root` roots in production (`build_template`/
    /// `test_template`, both `pkgs.writeText` outputs per
    /// `substrate/lib/infra/ami-build.nix`) is already a bare top-level
    /// store path, never a file nested inside a larger derivation. Using
    /// a top-level path here matches that shape.
    fn real_store_path_for_test() -> Option<PathBuf> {
        let which_output = Command::new("which").arg("nix-store").output().ok()?;
        if !which_output.status.success() {
            return None;
        }
        let nix_store_bin = PathBuf::from(String::from_utf8_lossy(&which_output.stdout).trim());
        let canon = std::fs::canonicalize(&nix_store_bin).ok()?;
        if !canon.starts_with("/nix/store") {
            // nix isn't installed via the standard /nix/store layout on
            // this machine -- skip rather than false-fail.
            return None;
        }
        // Truncate to the top-level /nix/store/<hash>-<name> component --
        // the 4th path component (["", "nix", "store", "<hash>-<name>"]).
        let components: Vec<_> = canon.components().collect();
        if components.len() < 4 {
            None
        } else {
            Some(components[..4].iter().collect())
        }
    }

    #[test]
    fn add_gc_root_creates_a_resolvable_root_pointing_at_the_target() {
        let Some(target) = real_store_path_for_test() else {
            eprintln!("skipping: not running under a nix-built binary (no /nix/store exe path)");
            return;
        };
        let root_dir = tempfile::Builder::new()
            .prefix("ami-forge-gcroot-test-")
            .tempdir()
            .expect("tempdir");

        add_gc_root(&target, root_dir.path(), "test-root").expect("add_gc_root should succeed against a real store path");

        let root_link = root_dir.path().join("test-root");
        assert!(root_link.exists(), "GC root symlink was not created at {}", root_link.display());
        let resolved = std::fs::canonicalize(&root_link).expect("root link should resolve");
        assert_eq!(
            resolved, target,
            "GC root at {} resolves to {} instead of the target {}",
            root_link.display(),
            resolved.display(),
            target.display()
        );

        // The load-bearing regression proof: nix itself must now consider
        // this path a live GC root, not just "a symlink exists on disk" —
        // `nix-store --gc --print-roots` is the same query the real
        // garbage collector consults before sweeping anything.
        let output = Command::new("nix-store")
            .args(["--gc", "--print-roots"])
            .output()
            .expect("failed to run nix-store --gc --print-roots");
        let roots = String::from_utf8_lossy(&output.stdout);
        assert!(
            roots.contains(&*target.to_string_lossy()),
            "target path {} does not appear in nix-store's own GC roots listing -- \
             the root we created would NOT actually protect it from a real collection",
            target.display()
        );
    }

    #[test]
    fn root_pipeline_inputs_roots_build_and_test_templates_together() {
        let Some(target) = real_store_path_for_test() else {
            eprintln!("skipping: not running under a nix-built binary (no /nix/store exe path)");
            return;
        };
        // Both build_template and test_template point at the SAME real
        // store path here -- the test only needs a real path to root, not
        // two distinct ones; the regression this proves is that
        // `root_pipeline_inputs` roots BOTH config fields, which is what
        // the original bug (test_template unrooted, build_template's own
        // path implicitly surviving because packer itself was still
        // reading it) actually needed.
        let config = PipelineConfig {
            build_template: target.clone(),
            test_template: target.clone(),
            ssm: "/test/ssm/path".into(),
            ami_name: "test-ami".into(),
            region: default_region(),
            cluster_test: None,
            manifest: default_manifest(),
            attic: None,
            make_public: false,
        };

        let gcroots = root_pipeline_inputs(&config).expect("root_pipeline_inputs should succeed");
        assert!(gcroots.path().join("build-template").exists());
        assert!(gcroots.path().join("test-template").exists());
    }
}
